# Shapes module - abstract base class implementing IMeasurable
from geometry_types import ShapeType, IMeasurable

@abstract
class Shape(IMeasurable):
    _type: ShapeType

    def __init__(self, shape_type: ShapeType):
        self._type = shape_type

    def get_type(self) -> ShapeType:
        return self._type

    @abstract
    def describe(self) -> str: ...

    @abstract
    def measure(self) -> float: ...

